  1→import type {
  2→  Block,
  3→  Conversation,
  4→  FormatRule,
  5→  Message,
  6→  RuleEffect,
  7→} from "@chat-exporter/shared";
  8→import { ClipboardCopy } from "lucide-react";
  9→import React, { memo, useCallback, useMemo, useRef, useState } from "react";
 10→import { ErrorBoundary } from "@/components/error-boundary";
 11→import { BlockErrorFallback } from "@/components/format-workspace/block-error-fallback";
 12→import { BlockInserter } from "@/components/format-workspace/block-inserter";
 13→import { BlockToolbar } from "@/components/format-workspace/block-toolbar";
 14→import { EditableBlock } from "@/components/format-workspace/editable-block";
 15→import { getRoleLabel } from "@/components/format-workspace/labels";
 16→import { MessageDeleteMenu } from "@/components/format-workspace/message-delete-menu";
 17→import {
 18→  blockToPlainText,
 19→  collectInserts,
 20→  getBlocksMatchingRule,
 21→  getReaderBlockClassName,
 22→  getReaderBlockStyle,
 23→  renderReaderBlock,
 24→} from "@/components/format-workspace/rule-engine";
 25→import type {
 26→  AdjustmentSelection,
 27→  ViewportAnchor,
 28→} from "@/components/format-workspace/types";
 29→import { cn } from "@/lib/utils";
 30→
 31→import {
 32→  SELECTION_DEBOUNCE_MS,
 33→  TEXT_PREVIEW_LIMIT,
 34→  TEXT_TRUNCATION_LIMIT,
 35→} from "./constants";
 36→
 37→/** Thin wrapper so that errors thrown by renderReaderBlock are caught by ErrorBoundary. */
 38→function BlockRenderer({
 39→  block,
 40→  effects,
 41→}: {
 42→  block: Block;
 43→  effects: RuleEffect[];
 44→}) {
 45→  return <>{renderReaderBlock(block, effects)}</>;
 46→}
 47→
 48→type ReaderViewProps = {
 49→  activeRules: FormatRule[];
 50→  adjustModeEnabled: boolean;
 51→  conversation: Conversation | undefined;
 52→  deletedMessageIds?: Set<string>;
 53→  editMode?: boolean;
 54→  effectsMap: Map<string, RuleEffect[]>;
 55→  highlightedRuleId: string | null;
 56→  onBlocksChange?: (messageId: string, blocks: Block[]) => void;
 57→  onCopyMessage?: (messageId: string) => void;
 58→  onDeleteMessage?: (messageId: string) => void;
 59→  onDeleteRound?: (messageId: string) => void;
 60→  onRestoreMessage?: (messageId: string) => Promise<{ restored: boolean }>;
 61→  onSelectBlock: (
 62→    selection: AdjustmentSelection,
 63→    anchor: ViewportAnchor,
 64→  ) => void;
 65→  selectedBlock: AdjustmentSelection | null;
 66→  showDeleted?: boolean;
 67→};
 68→
 69→function truncateSelectionText(value: string) {
 70→  return value.length > TEXT_TRUNCATION_LIMIT
 71→    ? `${value.slice(0, TEXT_PREVIEW_LIMIT).trimEnd()}...`
 72→    : value;
 73→}
 74→
 75→function toViewportAnchor(rect: DOMRect): ViewportAnchor {
 76→  return {
 77→    bottom: rect.bottom,
 78→    height: rect.height,
 79→    left: rect.left,
 80→    top: rect.top,
 81→    width: rect.width,
 82→  };
 83→}
 84→
 85→type ReaderMessageProps = {
 86→  adjustModeEnabled: boolean;
 87→  editMode?: boolean;
 88→  effectsMap: Map<string, RuleEffect[]>;
 89→  highlightedBlocks: Set<string>;
 90→  isDeleted?: boolean;
 91→  message: Message;
 92→  messageIndex: number;
 93→  onBlockChange?: (
 94→    messageId: string,
 95→    blockIndex: number,
 96→    newBlock: Block,
 97→  ) => void;
 98→  onBlocksChange?: (messageId: string, blocks: Block[]) => void;
 99→  onCopyMessage?: () => void;
100→  onDeleteMessage?: () => void;
101→  onDeleteRound?: () => void;
102→  onRestore?: () => void;
103→  onSelectBlock: ReaderViewProps["onSelectBlock"];
104→  selectedBlock: AdjustmentSelection | null;
105→};
106→
107→const ReaderMessage = memo(function ReaderMessage({
108→  adjustModeEnabled,
109→  editMode,
110→  effectsMap,
111→  highlightedBlocks,
112→  isDeleted,
113→  message,
114→  messageIndex,
115→  onBlockChange,
116→  onBlocksChange,
117→  onCopyMessage,
118→  onDeleteMessage,
119→  onDeleteRound,
120→  onRestore,
121→  onSelectBlock,
122→  selectedBlock,
123→}: ReaderMessageProps) {
124→  const lastSelectionInteractionAt = useRef(0);
125→  const [hoveredBlockIndex, setHoveredBlockIndex] = useState<number | null>(
126→    null,
127→  );
128→
129→  const handleDeleteBlock = useCallback(
130→    (blockIndex: number) => {
131→      if (!onBlocksChange) return;
132→      const updatedBlocks = [...message.blocks];
133→      updatedBlocks.splice(blockIndex, 1);
134→      onBlocksChange(message.id, updatedBlocks);
135→    },
136→    [message.blocks, message.id, onBlocksChange],
137→  );
138→
139→  const handleDuplicateBlock = useCallback(
140→    (blockIndex: number) => {
141→      if (!onBlocksChange) return;
142→      const updatedBlocks = [...message.blocks];
143→      const original = updatedBlocks[blockIndex];
144→      if (!original) return;
145→      const copy = { ...original } as Block;
146→      updatedBlocks.splice(blockIndex + 1, 0, copy);
147→      onBlocksChange(message.id, updatedBlocks);
148→    },
149→    [message.blocks, message.id, onBlocksChange],
150→  );
151→
152→  const handleMoveUp = useCallback(
153→    (blockIndex: number) => {
154→      if (!onBlocksChange || blockIndex === 0) return;
155→      const updatedBlocks = [...message.blocks];
156→      const current = updatedBlocks[blockIndex];
157→      const above = updatedBlocks[blockIndex - 1];
158→      if (!current || !above) return;
159→      updatedBlocks[blockIndex - 1] = current;
160→      updatedBlocks[blockIndex] = above;
161→      onBlocksChange(message.id, updatedBlocks);
162→    },
163→    [message.blocks, message.id, onBlocksChange],
164→  );
165→
166→  const handleMoveDown = useCallback(
167→    (blockIndex: number) => {
168→      if (!onBlocksChange || blockIndex >= message.blocks.length - 1) return;
169→      const updatedBlocks = [...message.blocks];
170→      const current = updatedBlocks[blockIndex];
171→      const below = updatedBlocks[blockIndex + 1];
172→      if (!current || !below) return;
173→      updatedBlocks[blockIndex] = below;
174→      updatedBlocks[blockIndex + 1] = current;
175→      onBlocksChange(message.id, updatedBlocks);
176→    },
177→    [message.blocks, message.id, onBlocksChange],
178→  );
179→
180→  const handleTypeChange = useCallback(
181→    (blockIndex: number, newBlock: Block) => {
182→      if (!onBlocksChange) return;
183→      const updatedBlocks = [...message.blocks];
184→      updatedBlocks[blockIndex] = newBlock;
185→      onBlocksChange(message.id, updatedBlocks);
186→    },
187→    [message.blocks, message.id, onBlocksChange],
188→  );
189→
190→  const handleInsertBlock = useCallback(
191→    (blockIndex: number, block: Block) => {
192→      if (!onBlocksChange) return;
193→      const updatedBlocks = [...message.blocks];
194→      updatedBlocks.splice(blockIndex, 0, block);
195→      onBlocksChange(message.id, updatedBlocks);
196→    },
197→    [message.blocks, message.id, onBlocksChange],
198→  );
199→
200→  return (
201→    <article
202→      className={cn(
203→        "rounded-[1.55rem] border border-border/80 px-4 py-5 sm:px-5",
204→        message.role === "assistant" ? "bg-card/92" : "bg-secondary/30",
205→        isDeleted && "opacity-50",
206→      )}
207→    >
208→      {isDeleted && (
209→        <div className="mb-3 flex items-center justify-between rounded-xl bg-red-50 border border-red-200/60 px-3 py-2 text-xs text-red-700">
210→          <span>Gelöscht</span>
211→          {onRestore && (
212→            <button
213→              type="button"
214→              className="text-red-600 hover:text-red-800 underline"
215→              onClick={(e) => {
216→                e.stopPropagation();
217→                onRestore();
218→              }}
219→            >
220→              Wiederherstellen
221→            </button>
222→          )}
223→        </div>
224→      )}
225→      <div className="mb-4 flex items-center gap-3 text-xs uppercase tracking-[0.18em] text-muted-foreground">
226→        <span>{getRoleLabel(message.role)}</span>
227→        <span>{messageIndex + 1}</span>
228→        {!isDeleted && (onDeleteMessage || onCopyMessage) && (
229→          <span className="ml-auto flex items-center gap-1">
230→            {onCopyMessage && (
231→              <button
232→                type="button"
233→                className="rounded-lg p-1.5 text-muted-foreground hover:bg-secondary/50 hover:text-foreground transition-colors"
234→                onClick={(e) => {
235→                  e.stopPropagation();
236→                  onCopyMessage();
237→                }}
238→                aria-label="Nachricht kopieren"
239→                data-testid={`copy-message-${message.id}`}
240→              >
241→                <ClipboardCopy className="h-4 w-4" />
242→              </button>
243→            )}
244→            {onDeleteMessage && onDeleteRound && (
245→              <MessageDeleteMenu
246→                onDeleteMessage={onDeleteMessage}
247→                onDeleteRound={onDeleteRound}
248→              />
249→            )}
250→          </span>
251→        )}
252→      </div>
253→      <div className="space-y-4">
254→        {editMode && onBlocksChange && (
255→          <BlockInserter blockIndex={0} onInsertBlock={handleInsertBlock} />
256→        )}
257→        {message.blocks.map((block, blockIndex) => {
258→          const blockText = blockToPlainText(block);
259→          const blockEffects =
260→            effectsMap.get(`${message.id}:${blockIndex}`) ?? [];
261→          const isSelected =
262→            selectedBlock?.messageId === message.id &&
263→            selectedBlock.blockIndex === blockIndex;
264→          const isHighlighted = highlightedBlocks.has(
265→            `${message.id}:${blockIndex}`,
266→          );
267→          const emitSelection = (
268→            anchor: ViewportAnchor,
269→            selectedText: string,
270→          ) => {
271→            lastSelectionInteractionAt.current = Date.now();
272→
273→            onSelectBlock(
274→              {
275→                blockIndex,
276→                blockType: block.type,
277→                messageId: message.id,
278→                messageIndex,
279→                messageRole: message.role,
280→                selectedText,
281→                textQuote: truncateSelectionText(selectedText),
282→              },
283→              anchor,
284→            );
285→          };
286→
287→          const inserts = collectInserts(blockEffects);
288→
289→          return (
290→            // biome-ignore lint/suspicious/noArrayIndexKey: block identity is message.id + blockIndex
291→            <React.Fragment key={`${message.id}-${blockIndex}`}>
292→              {inserts.insertBefore === "hr" && (
293→                <hr className="border-border/40" />
294→              )}
295→              {inserts.insertBefore === "spacer" && <div className="h-6" />}
296→              {/* biome-ignore lint/a11y/noStaticElementInteractions: hover tracking for block toolbar */}
297→              <div
298→                className="relative"
299→                onMouseEnter={() =>
300→                  editMode && setHoveredBlockIndex(blockIndex)
301→                }
302→                onMouseLeave={() => editMode && setHoveredBlockIndex(null)}
303→              >
304→                {editMode &&
305→                  onBlocksChange &&
306→                  hoveredBlockIndex === blockIndex && (
307→                    <BlockToolbar
308→                      block={block}
309→                      blockIndex={blockIndex}
310→                      totalBlocks={message.blocks.length}
311→                      onDelete={handleDeleteBlock}
312→                      onDuplicate={handleDuplicateBlock}
313→                      onMoveUp={handleMoveUp}
314→                      onMoveDown={handleMoveDown}
315→                      onTypeChange={handleTypeChange}
316→                    />
317→                  )}
318→                {/* biome-ignore lint/a11y/useKeyWithClickEvents: block selection is pointer-only by design */}
319→                {/* biome-ignore lint/a11y/noStaticElementInteractions: block selection uses onPointerUp + onClick */}
320→                <div
321→                  data-testid={`reader-block-${message.id}-${blockIndex}`}
322→                  className={getReaderBlockClassName({
323→                    adjustModeEnabled,
324→                    effects: blockEffects,
325→                    isHighlighted,
326→                    isSelected,
327→                  })}
328→                  style={getReaderBlockStyle(blockEffects)}
329→                  data-selected={isSelected ? "true" : "false"}
330→                  onPointerUp={(event) => {
331→                    if (!adjustModeEnabled) {
332→                      return;
333→                    }
334→
335→                    const selection = window.getSelection();
336→                    const range =
337→                      selection && selection.rangeCount > 0
338→                        ? selection.getRangeAt(0)
339→                        : null;
340→                    const selectedText = selection?.toString().trim() ?? "";
341→                    const container = event.currentTarget;
342→                    const rangeStartContainer = range?.startContainer ?? null;
343→                    const rangeEndContainer = range?.endContainer ?? null;
344→                    const hasLocalTextSelection =
345→                      Boolean(selectedText) &&
346→                      Boolean(rangeStartContainer) &&
347→                      Boolean(rangeEndContainer) &&
348→                      container.contains(rangeStartContainer) &&
349→                      container.contains(rangeEndContainer);
350→                    const anchorRect =
351→                      hasLocalTextSelection && range
352→                        ? range.getBoundingClientRect()
353→                        : container.getBoundingClientRect();
354→
355→                    emitSelection(
356→                      toViewportAnchor(anchorRect),
357→                      hasLocalTextSelection ? selectedText : blockText,
358→                    );
359→
360→                    if (selection && hasLocalTextSelection) {
361→                      selection.removeAllRanges();
362→                    }
363→                  }}
364→                  onClick={(event) => {
365→                    if (!adjustModeEnabled) {
366→                      return;
367→                    }
368→
369→                    if (
370→                      Date.now() - lastSelectionInteractionAt.current <
371→                      SELECTION_DEBOUNCE_MS
372→                    ) {
373→                      return;
374→                    }
375→
376→                    emitSelection(
377→                      toViewportAnchor(
378→                        event.currentTarget.getBoundingClientRect(),
379→                      ),
380→                      blockText,
381→                    );
382→                  }}
383→                >
384→                  <ErrorBoundary
385→                    fallback={<BlockErrorFallback blockType={block.type} />}
386→                  >
387→                    {editMode && onBlockChange ? (
388→                      <EditableBlock
389→                        block={block}
390→                        blockIndex={blockIndex}
391→                        messageId={message.id}
392→                        onBlockChange={onBlockChange}
393→                      >
394→                        <BlockRenderer block={block} effects={blockEffects} />
395→                      </EditableBlock>
396→                    ) : (
397→                      <BlockRenderer block={block} effects={blockEffects} />
398→                    )}
399→                  </ErrorBoundary>
400→                </div>
401→              </div>
402→              {inserts.insertAfter === "hr" && (
403→                <hr className="border-border/40" />
404→              )}
405→              {inserts.insertAfter === "spacer" && <div className="h-6" />}
406→              {editMode && onBlocksChange && (
407→                <BlockInserter
408→                  blockIndex={blockIndex + 1}
409→                  onInsertBlock={handleInsertBlock}
410→                />
411→              )}
412→            </React.Fragment>
413→          );
414→        })}
415→      </div>
416→    </article>
417→  );
418→});
419→
420→export function ReaderView({
421→  activeRules,
422→  adjustModeEnabled,
423→  conversation,
424→  deletedMessageIds,
425→  editMode,
426→  effectsMap,
427→  highlightedRuleId,
428→  onBlocksChange,
429→  onCopyMessage,
430→  onDeleteMessage,
431→  onDeleteRound,
432→  onRestoreMessage,
433→  onSelectBlock,
434→  selectedBlock,
435→  showDeleted,
436→}: ReaderViewProps) {
437→  const visibleMessages = useMemo(() => {
438→    if (!conversation?.messages) return [];
439→    if (!deletedMessageIds?.size) return conversation.messages;
440→    if (showDeleted) return conversation.messages;
441→    return conversation.messages.filter((m) => !deletedMessageIds.has(m.id));
442→  }, [conversation?.messages, deletedMessageIds, showDeleted]);
443→
444→  const highlightedBlocks = useMemo(() => {
445→    if (!highlightedRuleId || !conversation) {
446→      return new Set<string>();
447→    }
448→
449→    const rule = activeRules.find(
450→      (r) => r.id === highlightedRuleId && r.status === "active",
451→    );
452→
453→    if (!rule) {
454→      return new Set<string>();
455→    }
456→
457→    const matches = getBlocksMatchingRule(rule, conversation);
458→    return new Set(matches.map((m) => `${m.messageId}:${m.blockIndex}`));
459→  }, [highlightedRuleId, activeRules, conversation]);
460→
461→  const handleBlockChange = useCallback(
462→    (messageId: string, blockIndex: number, newBlock: Block) => {
463→      if (!onBlocksChange || !conversation) return;
464→      const message = conversation.messages.find((m) => m.id === messageId);
465→      if (!message) return;
466→      const updatedBlocks = message.blocks.map((b, i) =>
467→        i === blockIndex ? newBlock : b,
468→      );
469→      onBlocksChange(messageId, updatedBlocks);
470→    },
471→    [onBlocksChange, conversation],
472→  );
473→
474→  if (!conversation?.messages.length) {
475→    return (
476→      <div className="rounded-2xl border border-border/80 bg-card/75 px-4 py-5 text-sm text-muted-foreground">
477→        Für diesen Import ist noch kein Transkriptinhalt verfügbar.
478→      </div>
479→    );
480→  }
481→
482→  return (
483→    <div className="space-y-3">
484→      {visibleMessages.map((message, index) => (
485→        <ReaderMessage
486→          key={message.id}
487→          adjustModeEnabled={adjustModeEnabled}
488→          editMode={editMode}
489→          effectsMap={effectsMap}
490→          highlightedBlocks={highlightedBlocks}
491→          message={message}
492→          messageIndex={index}
493→          onBlockChange={editMode ? handleBlockChange : undefined}
494→          onBlocksChange={editMode ? onBlocksChange : undefined}
495→          onCopyMessage={
496→            onCopyMessage ? () => onCopyMessage(message.id) : undefined
497→          }
498→          onSelectBlock={onSelectBlock}
499→          selectedBlock={selectedBlock}
500→          isDeleted={deletedMessageIds?.has(message.id)}
501→          onDeleteMessage={
502→            onDeleteMessage ? () => onDeleteMessage(message.id) : undefined
503→          }
504→          onDeleteRound={
505→            onDeleteRound ? () => onDeleteRound(message.id) : undefined
506→          }
507→          onRestore={
508→            onRestoreMessage
509→              ? () => {
510→                  void onRestoreMessage(message.id);
511→                }
512→              : undefined
513→          }
514→        />
515→      ))}
516→    </div>
517→  );
518→}
