 57→function _describeSelectionLabel(selection: AdjustmentSelection) {
 58→  if (selection.lineStart !== undefined && selection.lineEnd !== undefined) {
 59→    return formatMarkdownLinesLabel(selection.lineStart, selection.lineEnd);
 60→  }
 61→
 62→  return formatMessageBlockLabel(
 63→    selection.messageRole,
 64→    selection.messageIndex + 1,
 65→    selection.blockType,
 66→  );
 67→}
 68→
 69→function renderArtifact(view: Exclude<ViewMode, "reader">, job: ImportJob) {
 70→  if (!job.artifacts) {
 71→    return "Artefakt ist noch nicht verfügbar.";
 72→  }
 73→
 74→  switch (view) {
 75→    case "markdown":
 76→      return job.artifacts.markdown;
 77→    case "handover":
 78→      return job.artifacts.handover;
 79→    case "json":
 80→      return job.artifacts.json;
 81→  }
 82→}
 83→
 84→export function FormatWorkspace({
 85→  activeStage,
 86→  elapsedTime,
 87→  job,
 88→  view,
 89→  onViewChange,
 90→}: FormatWorkspaceProps) {
 91→  const isAdjustableView = adjustableViews.has(view);
 92→
 93→  const session = useAdjustmentSession(view, job.id);
 94→  const rules = useFormatRules(view, job.id);
 95→  const snapshots = useSnapshots(job.id);
 96→  const messageEdits = useMessageEdits(job.id, snapshots.activeSnapshot?.id);
 97→  const resolvedMessages = useResolvedConversation(
 98→    job.conversation,
 99→    messageEdits.editedMessagesMap,
100→  );
101→  const autoSnapshot = useAutoSnapshot({
102→    activeSnapshot: snapshots.activeSnapshot,
103→    create: snapshots.create,
104→    activate: snapshots.activate,
105→  });
106→  const deletion = useMessageDeletion(job.id);
107→  const deletionToast = useDeletionToast();
108→  const [editMode, setEditMode] = useState<EditMode>("view");
109→
110→  // Mutual exclusion: edit mode and adjustment mode must never be active simultaneously
111→  const handleEditModeChange = useCallback(
112→    (mode: EditMode) => {
113→      if (mode === "edit" && session.adjustModeEnabled) {
114→        session.toggleAdjustMode();
115→      }
116→      setEditMode(mode);
117→    },
118→    [session],
119→  );
120→
121→  const handleToggleAdjustMode = useCallback(() => {
122→    if (!session.adjustModeEnabled && editMode === "edit") {
123→      setEditMode("view");
124→    }
125→    session.toggleAdjustMode();
126→  }, [session, editMode]);
127→
128→  const hasEdits = resolvedMessages.some((m) => m.isEdited);
129→
130→  // beforeunload warning when unsaved edits exist
131→  useEffect(() => {
132→    if (!messageEdits.isSaving) return;
133→    const handler = (e: BeforeUnloadEvent) => {
134→      e.preventDefault();
135→    };
136→    window.addEventListener("beforeunload", handler);
137→    return () => window.removeEventListener("beforeunload", handler);
138→  }, [messageEdits.isSaving]);
139→
140→  const handleBlocksChange = useCallback(
141→    (messageId: string, blocks: Block[]) => {
142→      void autoSnapshot.ensureSnapshot().then((ready) => {
143→        if (ready) {
144→          messageEdits.saveEdit(messageId, blocks);
145→        }
146→      });
147→    },
148→    [autoSnapshot, messageEdits],
149→  );
150→  const [versionsModalOpen, setVersionsModalOpen] = useState(false);
151→  const [deleteDialog, setDeleteDialog] = useState<{
152→    messageId: string;
153→    isRound: boolean;
154→    preview: string;
155→  } | null>(null);
156→  const popover = useAdjustmentPopover();
157→
158→  const handleDeleteMessage = useCallback(
159→    (messageId: string) => {
160→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
161→      const preview =
162→        msg?.blocks
163→          .map((b) => ("text" in b ? b.text : b.type))
164→          .join(" ")
165→          .slice(0, 200) ?? messageId;
166→      setDeleteDialog({ messageId, isRound: false, preview });
167→    },
168→    [job.conversation?.messages],
169→  );
170→
171→  const handleDeleteRound = useCallback(
172→    (messageId: string) => {
173→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
174→      const preview =
175→        msg?.blocks
176→          .map((b) => ("text" in b ? b.text : b.type))
177→          .join(" ")
178→          .slice(0, 200) ?? messageId;
179→      setDeleteDialog({ messageId, isRound: true, preview });
180→    },
181→    [job.conversation?.messages],
182→  );
183→
184→  const handleConfirmDelete = useCallback(
185→    async (reason?: string) => {
186→      if (!deleteDialog) return;
187→      const { messageId, isRound } = deleteDialog;
188→      setDeleteDialog(null);
189→      if (isRound) {
190→        const result = await deletion.deleteRound(messageId, reason);
191→        deletionToast.showDeletedToast(messageId, true, result.length);
192→      } else {
193→        await deletion.deleteMessage(messageId, reason);
194→        deletionToast.showDeletedToast(messageId, false);
195→      }
196→    },
197→    [deleteDialog, deletion, deletionToast],
198→  );
199→
200→  const handleUndoDelete = useCallback(async () => {
201→    if (!deletionToast.toast) return;
202→    await deletion.restoreMessage(deletionToast.toast.messageId);
203→    deletionToast.dismissToast();
204→  }, [deletion, deletionToast]);
205→
206→  const mergedRef = useCallback(
207→    (node: HTMLElement | null) => {
208→      (
209→        session.sectionRef as React.MutableRefObject<HTMLElement | null>
210→      ).current = node;
211→      (
212→        popover.containerRef as React.MutableRefObject<HTMLElement | null>
213→      ).current = node;
214→    },
215→    [session.sectionRef, popover.containerRef],
216→  );
217→
218→  const artifact = view === "reader" ? "" : renderArtifact(view, job);
219→  // Design-Entscheidung: Downloads erfolgen aus `displayedMarkdown`, das
220→  // `applyMarkdownRules` inklusive format_profile-Rules enthält. Der Server-
221→  // Endpoint `imports.exportArtifact` liefert hingegen rohe Artefakte ohne Rules.
222→  const displayedMarkdown = useMemo(() => {
223→    if (view !== "markdown") return artifact;
224→    try {
225→      return applyMarkdownRules(artifact, rules.activeRules);
226→    } catch {
227→      return artifact;
228→    }
229→  }, [artifact, rules.activeRules, view]);
230→
231→  const resolvedConversation = useMemo(() => {
232→    if (!job.conversation) return undefined;
233→    return {
234→      ...job.conversation,
235→      messages: resolvedMessages.map((rm) => ({
236→        id: rm.id,
237→        role: rm.role,
238→        blocks: rm.blocks,
239→      })),
240→    };
241→  }, [job.conversation, resolvedMessages]);
242→
243→  const readerEffectsMap = useMemo(
244→    () =>
245→      view === "reader" && resolvedConversation
246→        ? buildReaderEffectsMap(rules.activeRules, resolvedConversation)
247→        : new Map(),
248→    [rules.activeRules, resolvedConversation, view],
249→  );
250→
251→  const handleCopyMessage = useCallback(
252→    (messageId: string) => {
253→      const msg = resolvedConversation?.messages.find(
254→        (m) => m.id === messageId,
255→      );
256→      if (!msg) return;
257→      void copyMessageToClipboard(msg, view, msg.blocks);
258→    },
259→    [resolvedConversation, view],
260→  );
261→
262→  const handleDownload = useMemo(() => {
263→    if (view === "markdown") {
264→      return () => {
265→        const blob = new Blob([displayedMarkdown], { type: "text/markdown" });
266→        const url = URL.createObjectURL(blob);
267→        const a = document.createElement("a");
268→        a.href = url;
269→        a.download = `export-${job.id}.md`;
270→        document.body.appendChild(a);
271→        a.click();
272→        document.body.removeChild(a);
273→        setTimeout(() => URL.revokeObjectURL(url), 100);
274→      };
275→    }
276→    if (view === "reader" && resolvedConversation) {
277→      return () => {
278→        const html = resolvedConversation.messages
279→          .map((m) =>
280→            m.blocks
281→              .map((b) => ("text" in b ? b.text : JSON.stringify(b)))
282→              .join("\n"),
283→          )
284→          .join("\n\n---\n\n");
285→        const blob = new Blob([html], { type: "text/plain" });
286→        const url = URL.createObjectURL(blob);
287→        const a = document.createElement("a");
288→        a.href = url;
289→        a.download = `export-${job.id}.txt`;
290→        document.body.appendChild(a);
291→        a.click();
292→        document.body.removeChild(a);
293→        setTimeout(() => URL.revokeObjectURL(url), 100);
294→      };
295→    }
296→    if ((view === "handover" || view === "json") && artifact) {
297→      return () => {
298→        const ext = view === "json" ? "json" : "md";
299→        const blob = new Blob([artifact], { type: "text/plain" });
300→        const url = URL.createObjectURL(blob);
301→        const a = document.createElement("a");
302→        a.href = url;
303→        a.download = `export-${job.id}.${ext}`;
304→        document.body.appendChild(a);
305→        a.click();
306→        document.body.removeChild(a);
307→        setTimeout(() => URL.revokeObjectURL(url), 100);
308→      };
309→    }
310→    return undefined;
311→  }, [view, displayedMarkdown, job.id, resolvedConversation, artifact]);
312→  const showPopover =
313→    session.adjustModeEnabled &&
314→    Boolean(session.activeSelection) &&
315→    Boolean(session.activeAnchor);
316→
317→  const popoverCallbacksRef = useRef({
318→    handleDiscardSession: session.handleDiscardSession,
319→    activeSessionDetail: session.activeSessionDetail,
320→    handleRejectLastChange: rules.handleRejectLastChange,
321→    setReplyVisible: session.setReplyVisible,
322→  });
323→  popoverCallbacksRef.current = {
324→    handleDiscardSession: session.handleDiscardSession,
325→    activeSessionDetail: session.activeSessionDetail,
326→    handleRejectLastChange: rules.handleRejectLastChange,
327→    setReplyVisible: session.setReplyVisible,
328→  };
329→
330→  const handlePopoverClose = useCallback(() => {
331→    popoverCallbacksRef.current.handleDiscardSession();
332→  }, []);
333→
334→  const handleRejectLastChange = useCallback(() => {
335→    const {
336→      activeSessionDetail,
337→      handleRejectLastChange: reject,
338→      setReplyVisible,
339→    } = popoverCallbacksRef.current;
340→    if (activeSessionDetail) {
341→      void reject(activeSessionDetail).then((success) => {
342→        if (success) setReplyVisible(false);
343→      });
344→    }
345→  }, []);
346→
347→  const sessionError =
348→    session.activeSessionError ?? rules.disableError ?? rules.promoteError;
349→
350→  const viewErrorFallback = (_error: Error, reset: () => void) => (
351→    <div className="flex flex-col items-center justify-center gap-4 p-8 text-center">
