  9→function collectCustomStyles(effects: RuleEffect[]) {
 10→  const containerStyle: Record<string, string> = {};
 11→  const itemStyle: Record<string, string> = {};
 12→  const textStyle: Record<string, string> = {};
 13→  let textTransform: CustomStyleEffect["textTransform"] = null;
 14→  let headingLevel: number | undefined;
 15→
 16→  for (const effect of effects) {
 17→    if (effect.type !== "custom_style") continue;
 18→    if (effect.containerStyle)
 19→      Object.assign(containerStyle, effect.containerStyle);
 20→    if (effect.itemStyle) Object.assign(itemStyle, effect.itemStyle);
 21→    if (effect.textStyle) Object.assign(textStyle, effect.textStyle);
 22→    if (effect.textTransform) textTransform = effect.textTransform;
 23→    if (effect.headingLevel) headingLevel = effect.headingLevel;
 24→  }
 25→
 26→  return {
 27→    containerStyle:
 28→      Object.keys(containerStyle).length > 0 ? containerStyle : undefined,
 29→    itemStyle: Object.keys(itemStyle).length > 0 ? itemStyle : undefined,
 30→    textStyle: Object.keys(textStyle).length > 0 ? textStyle : undefined,
 31→    textTransform,
 32→    headingLevel,
 33→  };
 34→}
 35→
 36→export function collectInserts(effects: RuleEffect[]) {
 37→  let insertBefore: "hr" | "spacer" | null = null;
 38→  let insertAfter: "hr" | "spacer" | null = null;
 39→
 40→  for (const effect of effects) {
 41→    if (effect.type !== "custom_style") continue;
 42→    if (effect.insertBefore) insertBefore = effect.insertBefore;
 43→    if (effect.insertAfter) insertAfter = effect.insertAfter;
 44→  }
 45→
 46→  return { insertBefore, insertAfter };
 47→}
 48→
 49→export function blockToPlainText(block: Block) {
 50→  switch (block.type) {
 51→    case "paragraph":
 52→    case "heading":
 53→    case "quote":
 54→    case "code":
 55→      return block.text;
 56→    case "list":
 57→      return block.items.join(" ");
 58→    case "table":
 59→      return [
 60→        block.headers.join(" "),
 61→        ...block.rows.map((row) => row.join(" ")),
 62→      ].join(" ");
 63→  }
 64→}
 65→
 66→function renderTextWithBoldPrefix(text: string) {
 67→  const match = text.match(/^([^:\n]{1,120}:)(\s*)(.*)$/);
 68→
 69→  if (!match) {
 70→    return text;
 71→  }
 72→
 73→  return (
 74→    <>
 75→      <strong>{match[1]}</strong>
 76→      {match[2]}
 77→      {match[3]}
 78→    </>
 79→  );
 80→}
 81→
 82→function renderTextWithMarkdownStrong(text: string) {
 83→  const parts = text.split(/(\*\*[^*\n][^*\n]*\*\*|__[^_\n][^_\n]*__)/g);
 84→
 85→  if (parts.length === 1) {
 86→    return text;
 87→  }
 88→
 89→  return parts.map((part) => {
 90→    const strongMatch =
 91→      part.match(/^\*\*([^*\n][^*\n]*)\*\*$/) ??
 92→      part.match(/^__([^_\n][^_\n]*)__$/);
 93→
 94→    if (!strongMatch) {
