import type { Block, ImportJob } from "@chat-exporter/shared";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";

import { ErrorBoundary } from "@/components/error-boundary";
import { AdjustmentModeGuide } from "@/components/format-workspace/adjustment-mode-guide";
import { AdjustmentPopover } from "@/components/format-workspace/adjustment-popover";
import { ArtifactView } from "@/components/format-workspace/artifact-view";
import { CompletedToolbar } from "@/components/format-workspace/completed-toolbar";
import { DeleteMessageDialog } from "@/components/format-workspace/delete-message-dialog";
import {
  formatMarkdownLinesLabel,
  formatMessageBlockLabel,
  getImportStageLabel,
  miscLabels,
} from "@/components/format-workspace/labels";
import { LoadingStateBlock } from "@/components/format-workspace/loading-state-block";
import { MarkdownView } from "@/components/format-workspace/markdown-view";
import { ReaderView } from "@/components/format-workspace/reader-view";
import { copyMessageToClipboard } from "@/components/format-workspace/message-clipboard";
import {
  applyMarkdownRules,
  buildReaderEffectsMap,
} from "@/components/format-workspace/rule-engine";
import { SaveIndicator } from "@/components/format-workspace/save-indicator";
import { StatusHeader } from "@/components/format-workspace/status-header";
import {
  type AdjustmentSelection,
  adjustableViews,
  type EditMode,
  type ViewMode,
} from "@/components/format-workspace/types";
import { UndoToast } from "@/components/format-workspace/undo-toast";
import { useAdjustmentPopover } from "@/components/format-workspace/use-adjustment-popover";
import { useAdjustmentSession } from "@/components/format-workspace/use-adjustment-session";
import { useAutoSnapshot } from "@/components/format-workspace/use-auto-snapshot";
import { useDeletionToast } from "@/components/format-workspace/use-deletion-toast";
import { useFormatRules } from "@/components/format-workspace/use-format-rules";
import { useMessageDeletion } from "@/components/format-workspace/use-message-deletion";
import { useMessageEdits } from "@/components/format-workspace/use-message-edits";
import { useResolvedConversation } from "@/components/format-workspace/use-resolved-conversation";
import { useSnapshots } from "@/components/format-workspace/use-snapshots";
import { VersionsModal } from "@/components/format-workspace/versions-modal";

type ActiveStage = {
  detail: string;
  label: string;
} | null;

type FormatWorkspaceProps = {
  activeStage: ActiveStage;
  elapsedTime: string;
  job: ImportJob;
  view: ViewMode;
  onViewChange: (view: ViewMode) => void;
};

function _describeSelectionLabel(selection: AdjustmentSelection) {
  if (selection.lineStart !== undefined && selection.lineEnd !== undefined) {
    return formatMarkdownLinesLabel(selection.lineStart, selection.lineEnd);
  }

  return formatMessageBlockLabel(
    selection.messageRole,
    selection.messageIndex + 1,
    selection.blockType,
  );
}

function renderArtifact(view: Exclude<ViewMode, "reader">, job: ImportJob) {
  if (!job.artifacts) {
    return "Artefakt ist noch nicht verfügbar.";
  }

  switch (view) {
    case "markdown":
      return job.artifacts.markdown;
    case "handover":
      return job.artifacts.handover;
    case "json":
      return job.artifacts.json;
  }
}

export function FormatWorkspace({
  activeStage,
  elapsedTime,
  job,
  view,
  onViewChange,
}: FormatWorkspaceProps) {
  const isAdjustableView = adjustableViews.has(view);

  const session = useAdjustmentSession(view, job.id);
  const rules = useFormatRules(view, job.id);
  const snapshots = useSnapshots(job.id);
  const messageEdits = useMessageEdits(job.id, snapshots.activeSnapshot?.id);
  const resolvedMessages = useResolvedConversation(
    job.conversation,
    messageEdits.editedMessagesMap,
  );
  const autoSnapshot = useAutoSnapshot({
    activeSnapshot: snapshots.activeSnapshot,
    create: snapshots.create,
    activate: snapshots.activate,
  });
  const deletion = useMessageDeletion(job.id);
  const deletionToast = useDeletionToast();
  const [editMode, setEditMode] = useState<EditMode>("view");

  // Mutual exclusion: edit mode and adjustment mode must never be active simultaneously
  const handleEditModeChange = useCallback(
    (mode: EditMode) => {
      if (mode === "edit" && session.adjustModeEnabled) {
        session.toggleAdjustMode();
      }
      setEditMode(mode);
    },
    [session],
  );

  const handleToggleAdjustMode = useCallback(() => {
    if (!session.adjustModeEnabled && editMode === "edit") {
      setEditMode("view");
    }
    session.toggleAdjustMode();
  }, [session, editMode]);

  const hasEdits = resolvedMessages.some((m) => m.isEdited);

  // beforeunload warning when unsaved edits exist
  useEffect(() => {
    if (!messageEdits.isSaving) return;
    const handler = (e: BeforeUnloadEvent) => {
      e.preventDefault();
    };
    window.addEventListener("beforeunload", handler);
    return () => window.removeEventListener("beforeunload", handler);
  }, [messageEdits.isSaving]);

  const handleBlocksChange = useCallback(
    (messageId: string, blocks: Block[]) => {
      void autoSnapshot.ensureSnapshot().then((ready) => {
        if (ready) {
          messageEdits.saveEdit(messageId, blocks);
        }
      });
    },
    [autoSnapshot, messageEdits],
  );
  const [versionsModalOpen, setVersionsModalOpen] = useState(false);
  const [deleteDialog, setDeleteDialog] = useState<{
    messageId: string;
    isRound: boolean;
    preview: string;
  } | null>(null);
  const popover = useAdjustmentPopover();

  const handleDeleteMessage = useCallback(
    (messageId: string) => {
      const msg = job.conversation?.messages.find((m) => m.id === messageId);
      const preview =
        msg?.blocks
          .map((b) => ("text" in b ? b.text : b.type))
          .join(" ")
          .slice(0, 200) ?? messageId;
      setDeleteDialog({ messageId, isRound: false, preview });
    },
    [job.conversation?.messages],
  );

  const handleDeleteRound = useCallback(
    (messageId: string) => {
      const msg = job.conversation?.messages.find((m) => m.id === messageId);
      const preview =
        msg?.blocks
          .map((b) => ("text" in b ? b.text : b.type))
          .join(" ")
          .slice(0, 200) ?? messageId;
      setDeleteDialog({ messageId, isRound: true, preview });
    },
    [job.conversation?.messages],
  );

  const handleConfirmDelete = useCallback(
    async (reason?: string) => {
      if (!deleteDialog) return;
      const { messageId, isRound } = deleteDialog;
      setDeleteDialog(null);
      if (isRound) {
        const result = await deletion.deleteRound(messageId, reason);
        deletionToast.showDeletedToast(messageId, true, result.length);
      } else {
        await deletion.deleteMessage(messageId, reason);
        deletionToast.showDeletedToast(messageId, false);
      }
    },
    [deleteDialog, deletion, deletionToast],
  );

  const handleUndoDelete = useCallback(async () => {
    if (!deletionToast.toast) return;
    await deletion.restoreMessage(deletionToast.toast.messageId);
    deletionToast.dismissToast();
  }, [deletion, deletionToast]);

  const mergedRef = useCallback(
    (node: HTMLElement | null) => {
      (
        session.sectionRef as React.MutableRefObject<HTMLElement | null>
      ).current = node;
      (
        popover.containerRef as React.MutableRefObject<HTMLElement | null>
      ).current = node;
    },
    [session.sectionRef, popover.containerRef],
  );

  const artifact = view === "reader" ? "" : renderArtifact(view, job);
  // Design-Entscheidung: Downloads erfolgen aus `displayedMarkdown`, das
  // `applyMarkdownRules` inklusive format_profile-Rules enthält. Der Server-
  // Endpoint `imports.exportArtifact` liefert hingegen rohe Artefakte ohne Rules.
  const displayedMarkdown = useMemo(() => {
    if (view !== "markdown") return artifact;
    try {
      return applyMarkdownRules(artifact, rules.activeRules);
    } catch {
      return artifact;
    }
  }, [artifact, rules.activeRules, view]);

  const resolvedConversation = useMemo(() => {
    if (!job.conversation) return undefined;
    return {
      ...job.conversation,
      messages: resolvedMessages.map((rm) => ({
        id: rm.id,
        role: rm.role,
        blocks: rm.blocks,
      })),
    };
  }, [job.conversation, resolvedMessages]);

  const readerEffectsMap = useMemo(
    () =>
      view === "reader" && resolvedConversation
        ? buildReaderEffectsMap(rules.activeRules, resolvedConversation)
        : new Map(),
    [rules.activeRules, resolvedConversation, view],
  );

  const handleCopyMessage = useCallback(
    (messageId: string) => {
      const msg = resolvedConversation?.messages.find(
        (m) => m.id === messageId,
      );
      if (!msg) return;
      void copyMessageToClipboard(msg, view, msg.blocks);
    },
    [resolvedConversation, view],
  );

  const handleDownload = useMemo(() => {
    if (view === "markdown") {
      return () => {
        const blob = new Blob([displayedMarkdown], { type: "text/markdown" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `export-${job.id}.md`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        setTimeout(() => URL.revokeObjectURL(url), 100);
      };
    }
    if (view === "reader" && resolvedConversation) {
      return () => {
        const html = buildReaderHtml(
          resolvedConversation,
          readerEffectsMap,
          resolvedConversation.title ?? `export-${job.id}`,
        );
        const blob = new Blob([html], { type: "text/html" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `export-${job.id}.html`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        setTimeout(() => URL.revokeObjectURL(url), 100);
      };
    }
    if ((view === "handover" || view === "json") && artifact) {
      return () => {
        const ext = view === "json" ? "json" : "md";
        const blob = new Blob([artifact], { type: "text/plain" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `export-${job.id}.${ext}`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        setTimeout(() => URL.revokeObjectURL(url), 100);
      };
    }
    return undefined;
  }, [view, displayedMarkdown, job.id, resolvedConversation, artifact]);
  const showPopover =
    session.adjustModeEnabled &&
    Boolean(session.activeSelection) &&
    Boolean(session.activeAnchor);

  const popoverCallbacksRef = useRef({
    handleDiscardSession: session.handleDiscardSession,
    activeSessionDetail: session.activeSessionDetail,
    handleRejectLastChange: rules.handleRejectLastChange,
    setReplyVisible: session.setReplyVisible,
  });
  popoverCallbacksRef.current = {
    handleDiscardSession: session.handleDiscardSession,
    activeSessionDetail: session.activeSessionDetail,
    handleRejectLastChange: rules.handleRejectLastChange,
    setReplyVisible: session.setReplyVisible,
  };

  const handlePopoverClose = useCallback(() => {
    popoverCallbacksRef.current.handleDiscardSession();
  }, []);

  const handleRejectLastChange = useCallback(() => {
    const {
      activeSessionDetail,
      handleRejectLastChange: reject,
      setReplyVisible,
    } = popoverCallbacksRef.current;
    if (activeSessionDetail) {
      void reject(activeSessionDetail).then((success) => {
        if (success) setReplyVisible(false);
      });
    }
  }, []);

  const sessionError =
    session.activeSessionError ?? rules.disableError ?? rules.promoteError;

  const viewErrorFallback = (_error: Error, reset: () => void) => (
    <div className="flex flex-col items-center justify-center gap-4 p-8 text-center">
      <p className="text-red-700">{miscLabels.viewLoadError}</p>
      <button
        className="rounded-lg border border-border px-4 py-2 text-sm hover:bg-foreground/5"
        type="button"
        onClick={reset}
      >
        {miscLabels.retryButton}
      </button>
    </div>
  );

  return (
    <section
      ref={mergedRef}
      className="relative space-y-4 rounded-[1.9rem] border border-border/80 bg-background/70 p-4 sm:p-5"
    >
      <StatusHeader
        activeStage={activeStage}
        elapsedTime={elapsedTime}
        job={job}
      />

      {job.warnings.length > 0 ? (
        <div className="rounded-2xl border border-amber-300/40 bg-amber-100/60 px-4 py-3 text-sm text-amber-950">
          {job.warnings[0]}
        </div>
      ) : null}

      {job.status === "failed" ? (
        <div className="rounded-2xl border border-red-300/40 bg-red-100/70 p-4 text-red-900">
          <p className="font-medium">{miscLabels.importFailed}</p>
          {job.errorStage && job.errorStage !== "done" && (
            <p className="text-sm mt-1">
              {miscLabels.errorInPhase(getImportStageLabel(job.errorStage))}
            </p>
          )}
          {job.error && <p className="text-sm mt-1">{job.error}</p>}
        </div>
      ) : job.status === "queued" || job.status === "running" ? (
        <LoadingStateBlock stageDetail={activeStage?.detail} />
      ) : (
        <div className="space-y-4">
          <CompletedToolbar
            adjustModeEnabled={session.adjustModeEnabled}
            editMode={editMode}
            isAdjustableView={isAdjustableView}
            rules={rules}
            view={view}
            onDownloadMarkdown={handleDownload}
            onEditModeChange={handleEditModeChange}
            onToggleAdjustMode={handleToggleAdjustMode}
            onViewChange={onViewChange}
            deletionsCount={deletion.deletionsCount}
            showDeleted={deletion.showDeleted}
            snapshotCount={snapshots.snapshots.length}
            onVersionsClick={() => setVersionsModalOpen(true)}
            onToggleShowDeleted={() =>
              deletion.setShowDeleted(!deletion.showDeleted)
            }
          />

          {sessionError && !session.adjustModeEnabled ? (
            <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
              {sessionError}
            </div>
          ) : null}

          {view === "reader" ? (
            <ErrorBoundary fallback={viewErrorFallback}>
              <div className="space-y-2">
                <div className="flex justify-end">
                  <SaveIndicator
                    isSaving={messageEdits.isSaving}
                    hasEdits={hasEdits}
                  />
                </div>
                <ReaderView
                  activeRules={rules.activeRules}
                  conversation={resolvedConversation}
                  adjustModeEnabled={session.adjustModeEnabled}
                  editMode={editMode === "edit"}
                  effectsMap={readerEffectsMap}
                  highlightedRuleId={rules.hoveredRuleId}
                  selectedBlock={
                    view === "reader" ? session.activeSelection : null
                  }
                  onSelectBlock={session.handleSelectionChange}
                  deletedMessageIds={deletion.deletedMessageIds}
                  showDeleted={deletion.showDeleted}
                  onBlocksChange={handleBlocksChange}
                  onCopyMessage={handleCopyMessage}
                  onDeleteMessage={handleDeleteMessage}
                  onDeleteRound={handleDeleteRound}
                  onRestoreMessage={deletion.restoreMessage}
                />
              </div>
            </ErrorBoundary>
          ) : view === "markdown" ? (
            <ErrorBoundary fallback={viewErrorFallback}>
              <MarkdownView
                activeRules={rules.activeRules}
                content={displayedMarkdown}
                adjustModeEnabled={session.adjustModeEnabled}
                highlightedRuleId={rules.hoveredRuleId}
                selectedRange={session.activeSelection}
                onSelectLines={session.handleSelectionChange}
              />
            </ErrorBoundary>
          ) : (
            <ErrorBoundary fallback={viewErrorFallback}>
              <ArtifactView content={artifact} />
            </ErrorBoundary>
          )}

          {session.showGuide ? (
            <AdjustmentModeGuide
              view={view}
              onDismiss={() => session.setGuideDismissed(true)}
            />
          ) : null}

          <ErrorBoundary
            fallback={
              <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
                {miscLabels.adjustmentLoadError}
              </div>
            }
          >
            <AdjustmentPopover
              anchor={session.activeAnchor ?? null}
              containerRef={session.sectionRef}
              draftMessage={session.activeDraftMessage}
              error={session.activeSessionError}
              isLoading={session.activeSessionLoading || session.isDiscarding}
              isSubmitting={session.isSubmitting}
              open={
                showPopover &&
                Boolean(session.activeSelection) &&
                Boolean(session.activeAnchor)
              }
              sessionDetail={session.activeSessionDetail}
              showReply={session.replyVisible}
              view={view}
              onClose={handlePopoverClose}
              onDraftMessageChange={session.handleDraftMessageChange}
              onRejectLastChange={handleRejectLastChange}
              onSubmitMessage={session.handleSubmitMessage}
            />
          </ErrorBoundary>
        </div>
      )}

      {deleteDialog && (
        <DeleteMessageDialog
          messagePreview={deleteDialog.preview}
          isRound={deleteDialog.isRound}
          onConfirm={(reason) => {
            void handleConfirmDelete(reason);
          }}
          onCancel={() => setDeleteDialog(null)}
        />
      )}

      {deletionToast.toast && (
        <UndoToast
          message={deletionToast.toast.message}
          onUndo={() => {
            void handleUndoDelete();
          }}
          onDismiss={deletionToast.dismissToast}
        />
      )}

      <VersionsModal
        open={versionsModalOpen}
        onOpenChange={setVersionsModalOpen}
        snapshots={snapshots.snapshots}
        activeSnapshotId={snapshots.activeSnapshot?.id ?? null}
        onActivate={(snapshotId) => {
          void snapshots.activate(snapshotId);
        }}
        onDeactivate={() => {
          void snapshots.deactivate();
        }}
        onCreate={(label) => {
          void snapshots.create(label);
        }}
        onRename={(snapshotId, label) => {
          void snapshots.rename(snapshotId, label);
        }}
        onDelete={(snapshotId) => {
          void snapshots.delete(snapshotId);
        }}
      />
    </section>
  );
}

import type { Block, ImportJob } from "@chat-exporter/shared";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";

import { ErrorBoundary } from "@/components/error-boundary";
import { AdjustmentModeGuide } from "@/components/format-workspace/adjustment-mode-guide";
import { AdjustmentPopover } from "@/components/format-workspace/adjustment-popover";
import { ArtifactView } from "@/components/format-workspace/artifact-view";
import { CompletedToolbar } from "@/components/format-workspace/completed-toolbar";
import { DeleteMessageDialog } from "@/components/format-workspace/delete-message-dialog";
import {
  formatMarkdownLinesLabel,
  formatMessageBlockLabel,
  getImportStageLabel,
  miscLabels,
} from "@/components/format-workspace/labels";
import { LoadingStateBlock } from "@/components/format-workspace/loading-state-block";
import { MarkdownView } from "@/components/format-workspace/markdown-view";
import { ReaderView } from "@/components/format-workspace/reader-view";
import { copyMessageToClipboard } from "@/components/format-workspace/message-clipboard";
import { buildReaderHtml } from "@/components/format-workspace/reader-html-export";
import {
  applyMarkdownRules,
  buildReaderEffectsMap,
} from "@/components/format-workspace/rule-engine";
import { SaveIndicator } from "@/components/format-workspace/save-indicator";
import { StatusHeader } from "@/components/format-workspace/status-header";
import {
  type AdjustmentSelection,
  adjustableViews,
  type EditMode,
  type ViewMode,
} from "@/components/format-workspace/types";
import { UndoToast } from "@/components/format-workspace/undo-toast";
import { useAdjustmentPopover } from "@/components/format-workspace/use-adjustment-popover";
import { useAdjustmentSession } from "@/components/format-workspace/use-adjustment-session";
import { useAutoSnapshot } from "@/components/format-workspace/use-auto-snapshot";
import { useDeletionToast } from "@/components/format-workspace/use-deletion-toast";
import { useFormatRules } from "@/components/format-workspace/use-format-rules";
import { useMessageDeletion } from "@/components/format-workspace/use-message-deletion";
import { useMessageEdits } from "@/components/format-workspace/use-message-edits";
import { useResolvedConversation } from "@/components/format-workspace/use-resolved-conversation";
import { useSnapshots } from "@/components/format-workspace/use-snapshots";
import { VersionsModal } from "@/components/format-workspace/versions-modal";

type ActiveStage = {
  detail: string;
  label: string;
} | null;

type FormatWorkspaceProps = {
  activeStage: ActiveStage;
  elapsedTime: string;
  job: ImportJob;
  view: ViewMode;
  onViewChange: (view: ViewMode) => void;
};

function _describeSelectionLabel(selection: AdjustmentSelection) {
  if (selection.lineStart !== undefined && selection.lineEnd !== undefined) {
    return formatMarkdownLinesLabel(selection.lineStart, selection.lineEnd);
  }

  return formatMessageBlockLabel(
    selection.messageRole,
    selection.messageIndex + 1,
    selection.blockType,
  );
}

function renderArtifact(view: Exclude<ViewMode, "reader">, job: ImportJob) {
  if (!job.artifacts) {
    return "Artefakt ist noch nicht verfügbar.";
  }

  switch (view) {
    case "markdown":
      return job.artifacts.markdown;
    case "handover":
      return job.artifacts.handover;
    case "json":
      return job.artifacts.json;
  }
}

export function FormatWorkspace({
  activeStage,
  elapsedTime,
  job,
  view,
  onViewChange,
}: FormatWorkspaceProps) {
  const isAdjustableView = adjustableViews.has(view);

  const session = useAdjustmentSession(view, job.id);
  const rules = useFormatRules(view, job.id);
  const snapshots = useSnapshots(job.id);
  const messageEdits = useMessageEdits(job.id, snapshots.activeSnapshot?.id);
  const resolvedMessages = useResolvedConversation(
    job.conversation,
    messageEdits.editedMessagesMap,
  );
  const autoSnapshot = useAutoSnapshot({
    activeSnapshot: snapshots.activeSnapshot,
    create: snapshots.create,
    activate: snapshots.activate,
  });
  const deletion = useMessageDeletion(job.id);
  const deletionToast = useDeletionToast();
  const [editMode, setEditMode] = useState<EditMode>("view");

  // Mutual exclusion: edit mode and adjustment mode must never be active simultaneously
  const handleEditModeChange = useCallback(
    (mode: EditMode) => {
      if (mode === "edit" && session.adjustModeEnabled) {
        session.toggleAdjustMode();
      }
      setEditMode(mode);
    },
    [session],
  );

  const handleToggleAdjustMode = useCallback(() => {
    if (!session.adjustModeEnabled && editMode === "edit") {
      setEditMode("view");
    }
    session.toggleAdjustMode();
  }, [session, editMode]);

  const hasEdits = resolvedMessages.some((m) => m.isEdited);

  // beforeunload warning when unsaved edits exist
  useEffect(() => {
    if (!messageEdits.isSaving) return;
    const handler = (e: BeforeUnloadEvent) => {
      e.preventDefault();
    };
    window.addEventListener("beforeunload", handler);
    return () => window.removeEventListener("beforeunload", handler);
  }, [messageEdits.isSaving]);

  const handleBlocksChange = useCallback(
    (messageId: string, blocks: Block[]) => {
      void autoSnapshot.ensureSnapshot().then((ready) => {
        if (ready) {
          messageEdits.saveEdit(messageId, blocks);
        }
      });
    },
    [autoSnapshot, messageEdits],
  );
  const [versionsModalOpen, setVersionsModalOpen] = useState(false);
  const [deleteDialog, setDeleteDialog] = useState<{
    messageId: string;
    isRound: boolean;
    preview: string;
  } | null>(null);
  const popover = useAdjustmentPopover();

  const handleDeleteMessage = useCallback(
    (messageId: string) => {
      const msg = job.conversation?.messages.find((m) => m.id === messageId);
      const preview =
        msg?.blocks
          .map((b) => ("text" in b ? b.text : b.type))
          .join(" ")
          .slice(0, 200) ?? messageId;
      setDeleteDialog({ messageId, isRound: false, preview });
    },
    [job.conversation?.messages],
  );

  const handleDeleteRound = useCallback(
    (messageId: string) => {
      const msg = job.conversation?.messages.find((m) => m.id === messageId);
      const preview =
        msg?.blocks
          .map((b) => ("text" in b ? b.text : b.type))
          .join(" ")
          .slice(0, 200) ?? messageId;
      setDeleteDialog({ messageId, isRound: true, preview });
    },
    [job.conversation?.messages],
  );

  const handleConfirmDelete = useCallback(
    async (reason?: string) => {
      if (!deleteDialog) return;
      const { messageId, isRound } = deleteDialog;
      setDeleteDialog(null);
      if (isRound) {
        const result = await deletion.deleteRound(messageId, reason);
        deletionToast.showDeletedToast(messageId, true, result.length);
      } else {
        await deletion.deleteMessage(messageId, reason);
        deletionToast.showDeletedToast(messageId, false);
      }
    },
    [deleteDialog, deletion, deletionToast],
  );

  const handleUndoDelete = useCallback(async () => {
    if (!deletionToast.toast) return;
    await deletion.restoreMessage(deletionToast.toast.messageId);
    deletionToast.dismissToast();
  }, [deletion, deletionToast]);

  const mergedRef = useCallback(
    (node: HTMLElement | null) => {
      (
        session.sectionRef as React.MutableRefObject<HTMLElement | null>
      ).current = node;
      (
        popover.containerRef as React.MutableRefObject<HTMLElement | null>
      ).current = node;
    },
    [session.sectionRef, popover.containerRef],
  );

  const artifact = view === "reader" ? "" : renderArtifact(view, job);
  // Design-Entscheidung: Downloads erfolgen aus `displayedMarkdown`, das
  // `applyMarkdownRules` inklusive format_profile-Rules enthält. Der Server-
  // Endpoint `imports.exportArtifact` liefert hingegen rohe Artefakte ohne Rules.
  const displayedMarkdown = useMemo(() => {
    if (view !== "markdown") return artifact;
    try {
      return applyMarkdownRules(artifact, rules.activeRules);
    } catch {
      return artifact;
    }
  }, [artifact, rules.activeRules, view]);

  const resolvedConversation = useMemo(() => {
    if (!job.conversation) return undefined;
    return {
      ...job.conversation,
      messages: resolvedMessages.map((rm) => ({
        id: rm.id,
        role: rm.role,
        blocks: rm.blocks,
      })),
    };
  }, [job.conversation, resolvedMessages]);

  const readerEffectsMap = useMemo(
    () =>
      view === "reader" && resolvedConversation
        ? buildReaderEffectsMap(rules.activeRules, resolvedConversation)
        : new Map(),
    [rules.activeRules, resolvedConversation, view],
  );

  const handleCopyMessage = useCallback(
    (messageId: string) => {
      const msg = resolvedConversation?.messages.find(
        (m) => m.id === messageId,
      );
      if (!msg) return;
      void copyMessageToClipboard(msg, view, msg.blocks);
    },
    [resolvedConversation, view],
  );

  const handleDownload = useMemo(() => {
    if (view === "markdown") {
      return () => {
        const blob = new Blob([displayedMarkdown], { type: "text/markdown" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `export-${job.id}.md`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        setTimeout(() => URL.revokeObjectURL(url), 100);
      };
    }
    if (view === "reader" && resolvedConversation) {
      return () => {
        const html = buildReaderHtml(
          resolvedConversation,
          readerEffectsMap,
          resolvedConversation.title ?? `export-${job.id}`,
        );
        const blob = new Blob([html], { type: "text/html" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `export-${job.id}.html`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        setTimeout(() => URL.revokeObjectURL(url), 100);
      };
    }
    if ((view === "handover" || view === "json") && artifact) {
      return () => {
        const ext = view === "json" ? "json" : "md";
        const blob = new Blob([artifact], { type: "text/plain" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `export-${job.id}.${ext}`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        setTimeout(() => URL.revokeObjectURL(url), 100);
      };
    }
    return undefined;
  }, [view, displayedMarkdown, job.id, resolvedConversation, artifact]);
  const showPopover =
    session.adjustModeEnabled &&
    Boolean(session.activeSelection) &&
    Boolean(session.activeAnchor);

  const popoverCallbacksRef = useRef({
    handleDiscardSession: session.handleDiscardSession,
    activeSessionDetail: session.activeSessionDetail,
    handleRejectLastChange: rules.handleRejectLastChange,
    setReplyVisible: session.setReplyVisible,
  });
  popoverCallbacksRef.current = {
    handleDiscardSession: session.handleDiscardSession,
    activeSessionDetail: session.activeSessionDetail,
    handleRejectLastChange: rules.handleRejectLastChange,
    setReplyVisible: session.setReplyVisible,
  };

  const handlePopoverClose = useCallback(() => {
    popoverCallbacksRef.current.handleDiscardSession();
  }, []);

  const handleRejectLastChange = useCallback(() => {
    const {
      activeSessionDetail,
      handleRejectLastChange: reject,
      setReplyVisible,
    } = popoverCallbacksRef.current;
    if (activeSessionDetail) {
      void reject(activeSessionDetail).then((success) => {
        if (success) setReplyVisible(false);
      });
    }
  }, []);

  const sessionError =
    session.activeSessionError ?? rules.disableError ?? rules.promoteError;

  const viewErrorFallback = (_error: Error, reset: () => void) => (
    <div className="flex flex-col items-center justify-center gap-4 p-8 text-center">
      <p className="text-red-700">{miscLabels.viewLoadError}</p>
      <button
        className="rounded-lg border border-border px-4 py-2 text-sm hover:bg-foreground/5"
        type="button"
        onClick={reset}
      >
        {miscLabels.retryButton}
      </button>
    </div>
  );

  return (
    <section
      ref={mergedRef}
      className="relative space-y-4 rounded-[1.9rem] border border-border/80 bg-background/70 p-4 sm:p-5"
    >
      <StatusHeader
        activeStage={activeStage}
        elapsedTime={elapsedTime}
        job={job}
      />

      {job.warnings.length > 0 ? (
        <div className="rounded-2xl border border-amber-300/40 bg-amber-100/60 px-4 py-3 text-sm text-amber-950">
          {job.warnings[0]}
        </div>
      ) : null}

      {job.status === "failed" ? (
        <div className="rounded-2xl border border-red-300/40 bg-red-100/70 p-4 text-red-900">
          <p className="font-medium">{miscLabels.importFailed}</p>
          {job.errorStage && job.errorStage !== "done" && (
            <p className="text-sm mt-1">
              {miscLabels.errorInPhase(getImportStageLabel(job.errorStage))}
            </p>
          )}
          {job.error && <p className="text-sm mt-1">{job.error}</p>}
        </div>
      ) : job.status === "queued" || job.status === "running" ? (
        <LoadingStateBlock stageDetail={activeStage?.detail} />
      ) : (
        <div className="space-y-4">
          <CompletedToolbar
            adjustModeEnabled={session.adjustModeEnabled}
            editMode={editMode}
            isAdjustableView={isAdjustableView}
            rules={rules}
            view={view}
            onDownloadMarkdown={handleDownload}
            onEditModeChange={handleEditModeChange}
            onToggleAdjustMode={handleToggleAdjustMode}
            onViewChange={onViewChange}
            deletionsCount={deletion.deletionsCount}
            showDeleted={deletion.showDeleted}
            snapshotCount={snapshots.snapshots.length}
            onVersionsClick={() => setVersionsModalOpen(true)}
            onToggleShowDeleted={() =>
              deletion.setShowDeleted(!deletion.showDeleted)
            }
          />

          {sessionError && !session.adjustModeEnabled ? (
            <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
              {sessionError}
            </div>
          ) : null}

          {view === "reader" ? (
            <ErrorBoundary fallback={viewErrorFallback}>
              <div className="space-y-2">
                <div className="flex justify-end">
                  <SaveIndicator
                    isSaving={messageEdits.isSaving}
                    hasEdits={hasEdits}
                  />
                </div>
                <ReaderView
                  activeRules={rules.activeRules}
                  conversation={resolvedConversation}
                  adjustModeEnabled={session.adjustModeEnabled}
                  editMode={editMode === "edit"}
                  effectsMap={readerEffectsMap}
                  highlightedRuleId={rules.hoveredRuleId}
                  selectedBlock={
                    view === "reader" ? session.activeSelection : null
                  }
                  onSelectBlock={session.handleSelectionChange}
                  deletedMessageIds={deletion.deletedMessageIds}
                  showDeleted={deletion.showDeleted}
                  onBlocksChange={handleBlocksChange}
                  onCopyMessage={handleCopyMessage}
                  onDeleteMessage={handleDeleteMessage}
                  onDeleteRound={handleDeleteRound}
                  onRestoreMessage={deletion.restoreMessage}
                />
              </div>
            </ErrorBoundary>
          ) : view === "markdown" ? (
            <ErrorBoundary fallback={viewErrorFallback}>
              <MarkdownView
                activeRules={rules.activeRules}
                content={displayedMarkdown}
                adjustModeEnabled={session.adjustModeEnabled}
                highlightedRuleId={rules.hoveredRuleId}
                selectedRange={session.activeSelection}
                onSelectLines={session.handleSelectionChange}
              />
            </ErrorBoundary>
          ) : (
            <ErrorBoundary fallback={viewErrorFallback}>
              <ArtifactView content={artifact} />
            </ErrorBoundary>
          )}

          {session.showGuide ? (
            <AdjustmentModeGuide
              view={view}
              onDismiss={() => session.setGuideDismissed(true)}
            />
          ) : null}

          <ErrorBoundary
            fallback={
              <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
                {miscLabels.adjustmentLoadError}
              </div>
            }
          >
            <AdjustmentPopover
              anchor={session.activeAnchor ?? null}
              containerRef={session.sectionRef}
              draftMessage={session.activeDraftMessage}
              error={session.activeSessionError}
              isLoading={session.activeSessionLoading || session.isDiscarding}
              isSubmitting={session.isSubmitting}
              open={
                showPopover &&
                Boolean(session.activeSelection) &&
                Boolean(session.activeAnchor)
              }
              sessionDetail={session.activeSessionDetail}
              showReply={session.replyVisible}
              view={view}
              onClose={handlePopoverClose}
              onDraftMessageChange={session.handleDraftMessageChange}
              onRejectLastChange={handleRejectLastChange}
              onSubmitMessage={session.handleSubmitMessage}
            />
          </ErrorBoundary>
        </div>
      )}

      {deleteDialog && (
        <DeleteMessageDialog
          messagePreview={deleteDialog.preview}
          isRound={deleteDialog.isRound}
          onConfirm={(reason) => {
            void handleConfirmDelete(reason);
          }}
          onCancel={() => setDeleteDialog(null)}
        />
      )}

      {deletionToast.toast && (
        <UndoToast
          message={deletionToast.toast.message}
          onUndo={() => {
            void handleUndoDelete();
          }}
          onDismiss={deletionToast.dismissToast}
        />
      )}

      <VersionsModal
        open={versionsModalOpen}
        onOpenChange={setVersionsModalOpen}
        snapshots={snapshots.snapshots}
        activeSnapshotId={snapshots.activeSnapshot?.id ?? null}
        onActivate={(snapshotId) => {
          void snapshots.activate(snapshotId);
        }}
        onDeactivate={() => {
          void snapshots.deactivate();
        }}
        onCreate={(label) => {
          void snapshots.create(label);
        }}
        onRename={(snapshotId, label) => {
          void snapshots.rename(snapshotId, label);
        }}
        onDelete={(snapshotId) => {
          void snapshots.delete(snapshotId);
        }}
      />
    </section>
  );
}

import type { Block, Conversation, RuleEffect } from "@chat-exporter/shared";

const ROLE_LABELS: Record<string, string> = {
  assistant: "Assistent",
  system: "System",
  tool: "Werkzeug",
  user: "Nutzer",
};

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function renderMarkdownStrong(text: string): string {
  return escapeHtml(text).replace(
    /\*\*([^*\n][^*\n]*)\*\*/g,
    "<strong>$1</strong>",
  );
}

function renderBlockHtml(block: Block): string {
  switch (block.type) {
    case "paragraph": {
      const numberedBoldMatch = block.text.match(
        /^\*\*(\d+\.\s.+?)\*\*\s*([\s\S]*)$/,
      );
      if (numberedBoldMatch) {
        const heading = escapeHtml(numberedBoldMatch[1]);
        const rest = numberedBoldMatch[2]?.trim();
        let html = `<hr class="block-hr"><h2 class="block-heading">${heading}</h2>`;
        if (rest) {
          html += `<p class="block-paragraph">${renderMarkdownStrong(rest)}</p>`;
        }
        return html;
      }
      return `<p class="block-paragraph">${renderMarkdownStrong(block.text)}</p>`;
    }
    case "heading": {
      const level = Math.min(block.level, 6);
      return `<h${level} class="block-heading">${renderMarkdownStrong(block.text)}</h${level}>`;
    }
    case "list":
      return `<ul class="block-list">${block.items.map((item) => `<li>${renderMarkdownStrong(item)}</li>`).join("")}</ul>`;
    case "quote":
      return `<blockquote class="block-quote">${renderMarkdownStrong(block.text)}</blockquote>`;
    case "code":
      return `<div class="block-code">${block.language ? `<p class="code-lang">${escapeHtml(block.language)}</p>` : ""}<pre><code>${escapeHtml(block.text)}</code></pre></div>`;
    case "table":
      return `<div class="block-table-wrap"><table class="block-table"><thead><tr>${block.headers.map((h) => `<th>${escapeHtml(h)}</th>`).join("")}</tr></thead><tbody>${block.rows.map((row) => `<tr>${row.map((cell) => `<td>${escapeHtml(cell)}</td>`).join("")}</tr>`).join("")}</tbody></table></div>`;
  }
}

function renderMessageHtml(
  message: Conversation["messages"][number],
  index: number,
  effectsMap: Map<string, RuleEffect[]>,
): string {
  const roleClass =
    message.role === "assistant" ? "msg-assistant" : "msg-user";
  const roleLabel = ROLE_LABELS[message.role] ?? message.role;

  const blocksHtml = message.blocks
    .map((block, blockIndex) => {
      const effects = effectsMap.get(`${message.id}:${blockIndex}`) ?? [];
      const style = collectContainerStyle(effects);
      const styleAttr = style ? ` style="${style}"` : "";
      return `<div class="block-wrapper"${styleAttr}>${renderBlockHtml(block)}</div>`;
    })
    .join("\n");

  return `<article class="message ${roleClass}">
  <div class="msg-header">
    <span>${escapeHtml(roleLabel)}</span>
    <span>${index + 1}</span>
  </div>
  <div class="msg-blocks">
${blocksHtml}
  </div>
</article>`;
}

function collectContainerStyle(effects: RuleEffect[]): string {
  const styles: Record<string, string> = {};
  for (const effect of effects) {
    if (effect.type !== "custom_style") continue;
    if (effect.containerStyle) Object.assign(styles, effect.containerStyle);
  }
  return Object.entries(styles)
    .map(([k, v]) => `${camelToKebab(k)}: ${v}`)
    .join("; ");
}

function camelToKebab(str: string): string {
  return str.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`);
}

const CSS = `
:root {
  --background: hsl(36 45% 97%);
  --foreground: hsl(195 28% 11%);
  --card: hsl(0 0% 100%);
  --secondary: hsl(38 40% 92%);
  --secondary-fg: hsl(192 30% 16%);
  --muted-fg: hsl(194 12% 42%);
  --primary: hsl(177 70% 26%);
  --accent: hsl(28 95% 58%);
  --border: hsl(192 24% 84%);
  --radius: 1.15rem;
}

*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  color-scheme: light;
}

body {
  font-family: "IBM Plex Sans", "Avenir Next", "Segoe UI", sans-serif;
  color: var(--foreground);
  background:
    radial-gradient(circle at top left, hsl(28 95% 58% / 0.16), transparent 30%),
    radial-gradient(circle at 90% 10%, hsl(177 70% 26% / 0.16), transparent 24%),
    linear-gradient(180deg, var(--background), hsl(35 35% 94%));
  min-height: 100vh;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  line-height: 1.5;
}

code, pre {
  font-family: "JetBrains Mono", "SFMono-Regular", "Menlo", monospace;
}

.container {
  max-width: 48rem;
  margin: 0 auto;
  padding: 2rem 1rem;
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.message {
  border-radius: 1.55rem;
  border: 1px solid var(--border);
  padding: 1.25rem 1.25rem;
}

.msg-assistant {
  background: hsl(0 0% 100% / 0.92);
}

.msg-user {
  background: hsl(38 40% 92% / 0.3);
}

.msg-header {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  margin-bottom: 1rem;
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.18em;
  color: var(--muted-fg);
}

.msg-blocks {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.block-wrapper {
  border-radius: calc(var(--radius) + 0.5rem);
  padding: 0.5rem 0.75rem;
}

.block-paragraph {
  font-size: 0.875rem;
  line-height: 1.75rem;
  color: hsl(195 28% 11% / 0.9);
}

.block-heading {
  font-weight: 600;
  color: var(--foreground);
}

h1.block-heading { font-size: 1.5rem; }
h2.block-heading { font-size: 1.25rem; }
h3.block-heading { font-size: 1.125rem; }
h4.block-heading { font-size: 1rem; }
h5.block-heading { font-size: 0.875rem; }
h6.block-heading { font-size: 0.8rem; }

.block-list {
  list-style: disc;
  padding-left: 1.25rem;
  font-size: 0.875rem;
  line-height: 1.75rem;
  color: hsl(195 28% 11% / 0.9);
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.block-quote {
  border-left: 2px solid var(--accent);
  padding-left: 1rem;
  font-size: 0.875rem;
  font-style: italic;
  line-height: 1.75rem;
  color: hsl(195 28% 11% / 0.8);
}

.block-code {
  border-radius: calc(var(--radius) + 0.5rem);
  border: 1px solid var(--border);
  background: hsl(240 6% 7%);
  padding: 1rem;
  font-size: 0.875rem;
  color: hsl(0 0% 96%);
}

.code-lang {
  margin-bottom: 0.75rem;
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.22em;
  color: hsl(240 5% 65%);
}

.block-code pre {
  overflow-x: auto;
  white-space: pre-wrap;
  word-break: break-word;
}

.block-table-wrap {
  overflow-x: auto;
  border-radius: calc(var(--radius) + 0.5rem);
  border: 1px solid var(--border);
}

.block-table {
  min-width: 100%;
  text-align: left;
  font-size: 0.875rem;
  border-collapse: collapse;
}

.block-table thead {
  background: hsl(38 40% 92% / 0.7);
  color: var(--secondary-fg);
}

.block-table th {
  padding: 0.75rem 1rem;
  font-weight: 500;
}

.block-table tbody tr {
  border-top: 1px solid var(--border);
}

.block-table td {
  padding: 0.75rem 1rem;
  vertical-align: top;
  color: var(--muted-fg);
}

.block-hr {
  margin-top: 2rem;
  border: none;
  border-top: 1px solid hsl(192 24% 84% / 0.4);
}

.export-footer {
  text-align: center;
  font-size: 0.7rem;
  color: var(--muted-fg);
  padding: 2rem 0 1rem;
}
`;

export function buildReaderHtml(
  conversation: Conversation,
  effectsMap: Map<string, RuleEffect[]>,
  title?: string,
): string {
  const pageTitle = title ?? "Chat Export — Reader";

  const messagesHtml = conversation.messages
    .map((message, index) => renderMessageHtml(message, index, effectsMap))
    .join("\n");

  return `<!DOCTYPE html>
<html lang="de">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>${escapeHtml(pageTitle)}</title>
  <link rel="preconnect" href="https://fonts.googleapis.com">
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
  <link href="https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@400;600;700&family=JetBrains+Mono:wght@400&display=swap" rel="stylesheet">
  <style>${CSS}</style>
</head>
<body>
  <div class="container">
${messagesHtml}
  </div>
  <p class="export-footer">Exportiert mit Chat Exporter</p>
</body>
</html>`;
}

